import{G as e,c as t,b as s,ae as i}from"./chunks/framework.Cpb2nuHT.js";const c=JSON.parse('{"title":"AES加密结果有+号浏览器转义后解密失败","description":"","frontmatter":{"title":"AES加密结果有+号浏览器转义后解密失败","date":"2025/4/17","author":"花木凋零成兰","tags":["Java","AES加密"],"cover":false,"hiddenCover":true},"headers":[],"relativePath":"后端开发问题/AES加密结果有+号浏览器转义后解密失败.md","filePath":"后端开发问题/AES加密结果有+号浏览器转义后解密失败.md","lastUpdated":1773124857000}'),o={name:"后端开发问题/AES加密结果有+号浏览器转义后解密失败.md"};function r(n,a,l,d,h,p){return s(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1744848000000"},[...a[0]||(a[0]=[i('<h1 id="aes加密结果有-号浏览器转义后解密失败" tabindex="-1">AES加密结果有+号浏览器转义后解密失败 <a class="header-anchor" href="#aes加密结果有-号浏览器转义后解密失败" aria-label="Permalink to &quot;AES加密结果有+号浏览器转义后解密失败&quot;">​</a></h1><h2 id="原因描述" tabindex="-1">原因描述 <a class="header-anchor" href="#原因描述" aria-label="Permalink to &quot;原因描述&quot;">​</a></h2><p>在开发某功能时, 要求提供一个跳转链接让用户通过点击可以跳转; 对该跳转链接参数进行拼接时某参数要求用AES加密后的字符串, 问题出在加密后的字符串携带&quot;+&quot;符号; 而该符号在浏览器中会被替换为空格并转移为&#39;%20&#39;;</p><p>此时跳转链接点击后,在浏览器中改加密参数中的&quot;+&quot;被替换为了&quot;%20&quot;空格转义符号, 后台接收到加密参数进行解密时会出现解密错误(因为有字符被替换).</p><p>实际上&quot;+&quot;号转义后应该为: &quot;%2B&quot;, 因为<strong>浏览器替换为 &quot;%20&quot; 空格转义导致后台接收到的符号变成了空格</strong>, 对加密参数进行解密时就会出现解密错误(因为有字符被替换).</p><h2 id="问题解决" tabindex="-1">问题解决 <a class="header-anchor" href="#问题解决" aria-label="Permalink to &quot;问题解决&quot;">​</a></h2><p>在构造跳转链接时, <strong>提前将加密后的字符串进行转义</strong>, 如此对于浏览器来说, 输入的参数中包含的不是&quot;+&quot;, 而是&quot;+&quot;转义后的字符, 如此就不会替换为空格;</p><p>在Java中, 可以调用JDK自带的路径编码API, 如下所示:</p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">URLEncoder.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">encode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(aesEncode, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;UTF-8&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/shiyong1949/article/details/79654995" target="_blank" rel="noreferrer">解决URL传参带加号“+”被转换为空格的办法</a></li></ul>',11)])])}const _=e(o,[["render",r]]);export{c as __pageData,_ as default};
